import { useEffect, useRef } from 'react'
import { Badge } from '@/components/ui/badge'
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible'
import { Bot, ChevronRight, Code2, MessageSquare, User, Zap } from 'lucide-react'
