export const TurnTranscriptSection = ({
  chatHistory: chatHistoryProp,
  metrics: metricsProp,
  highlightedTurn: highlightedTurnProp,
  embedded,
  alignment = 'chat',
}: {
  chatHistory?: ChatItem[] | null
  metrics?: SessionMetrics | null
  highlightedTurn?: number | null
  embedded?: boolean
  alignment?: TranscriptAlignment
}) => {
  const hook = useTranscript()
  const chatHistory = chatHistoryProp ?? hook.chatHistory
  const metrics = metricsProp ?? hook.metrics
  const highlightedTurn = highlightedTurnProp ?? hook.highlightedTurn

  const turnRefs = useRef<Record<number, HTMLDivElement | null>>({})

  useEffect(() => {
    if (highlightedTurn == null) return
    const el = turnRefs.current[highlightedTurn]
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'nearest' })
    }
  }, [highlightedTurn])

  // If we have structured turn data from metrics, show that
  if (metrics?.turns?.length) {
    const content = (
      <>
        <div className="flex items-center gap-2 mb-5">
          <MessageSquare size={15} className="text-muted-foreground" />
          <span className="text-s-400 font-medium">Conversation</span>
          <span className="text-xs text-muted-foreground">
            {metrics.turns.length} turn{metrics.turns.length !== 1 ? 's' : ''}
          </span>
        </div>
        <div className="mx-auto max-w-3xl flex flex-col">
          {metrics.turns.map((turn, i) => (
            <TurnCard
              key={turn.turn_id || i}
              turn={turn}
              highlighted={highlightedTurn === turn.turn_number}
              turnRef={(el) => { turnRefs.current[turn.turn_number] = el }}
              alignment={alignment}
            />
          ))}
        </div>
      </>
    )

    if (embedded) return content
    return <div className="rounded-lg border bg-card p-5">{content}</div>
  }

  // Fallback to raw chat history
  if (chatHistory?.length) {
    const messages = chatHistory.filter((item) => item.type === 'message')
    return (
      <div className="space-y-3">
        <div className="flex items-center gap-2">
          <MessageSquare size={15} className="text-muted-foreground" />
          <span className="text-s-400 font-medium">Transcript</span>
          <span className="text-xs text-muted-foreground">({messages.length} messages)</span>
        </div>
        <div className="space-y-1 max-h-[600px] overflow-y-auto">
          {messages.map((item, i) => (
            <ChatMessageCard key={item.id || i} item={item} />
          ))}
        </div>
      </div>
    )
  }

  return (
    <div className="flex items-center justify-center p-12 text-muted-foreground text-s-400">
      No turn data available
    </div>
  )
}

import { useCallback, useMemo, useRef, useState } from 'react'
import type { SessionMetrics } from '@/lib/observability-types'
import { useTimeline } from '@/lib/observability-hooks'
import { RECORDING_LABEL_WIDTH, RecordingPlayer } from './recording-player'
import { computeSessionBounds, computeTickInterval, SessionTrace, TimeAxis } from './session-trace'

interface SessionTimelineProps {
  metrics?: SessionMetrics | null
  recordUrl?: string | null | undefined
  onTurnClick?: (turnNumber: number) => void
  sessionCreatedAt?: string
}

export function SessionTimeline({
  metrics: metricsProp,
  recordUrl: recordUrlProp,
  onTurnClick: onTurnClickProp,
  sessionCreatedAt: sessionCreatedAtProp,
}: SessionTimelineProps) {
  const hook = useTimeline()
  const metrics = metricsProp ?? hook.metrics
  const recordUrl = recordUrlProp ?? hook.recordUrl
  const sessionCreatedAt = sessionCreatedAtProp ?? hook.sessionCreatedAt
  const onTurnClick = onTurnClickProp ?? hook.setHighlightedTurn

  const [audioDurationMs, setAudioDurationMs] = useState(0)
  const [currentTimeMs, setCurrentTimeMs] = useState(0)
  const cursorRef = useRef<HTMLDivElement>(null)
  const [controlsEl, setControlsEl] = useState<HTMLDivElement | null>(null)

  const traceBounds = useMemo(() => computeSessionBounds(metrics), [metrics])
  const totalMs = audioDurationMs > 0 ? audioDurationMs : traceBounds.totalMs
  const totalMsRef = useRef(totalMs)
  totalMsRef.current = totalMs

  const recordingOffsetMs = useMemo(() => {
    if (!sessionCreatedAt || !recordUrl || traceBounds.sessionStartMs === 0) return 0
    const createdMs = new Date(sessionCreatedAt).getTime()
    if (Number.isNaN(createdMs) || createdMs <= 0) return 0
    return Math.max(0, traceBounds.sessionStartMs - createdMs)
  }, [sessionCreatedAt, recordUrl, traceBounds.sessionStartMs])
  const tickInterval = computeTickInterval(totalMs)

  const handleTimeUpdate = useCallback((timeMs: number) => {
    setCurrentTimeMs(timeMs)
    const total = totalMsRef.current
    if (cursorRef.current && total > 0) {
      cursorRef.current.style.left = `${(timeMs / total) * 100}%`
    }
  }, [])

  const handleReady = useCallback((durationMs: number) => {
    setAudioDurationMs(durationMs)
  }, [])

  const handleSeek = useCallback((timeMs: number) => {
    setCurrentTimeMs(timeMs)
  }, [])

  const hasRecording = !!recordUrl
  const hasTrace = traceBounds.totalMs > 0

  if (!hasTrace && !hasRecording) {
    return (
      <div className="flex items-center justify-center h-20 text-[13px] text-muted-foreground">
        No trace data available
      </div>
    )
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-1">
        <div>
          <span className="text-[14px] font-medium">Session Timeline</span>
          <p className="text-[12px] text-muted-foreground mt-0.5">
            Turn-by-turn trace · click a turn to expand pipeline
          </p>
        </div>
        {hasRecording && <div ref={setControlsEl} />}
      </div>

      <div className="mt-4">
        <div className="relative">
          {hasRecording && (
            <RecordingPlayer
              recordUrl={recordUrl}
              embedded
              labelWidth={RECORDING_LABEL_WIDTH}
              onTimeUpdate={handleTimeUpdate}
              onReady={handleReady}
              onSeek={handleSeek}
              controlsContainer={controlsEl}
            />
          )}
          <div style={hasRecording ? { paddingLeft: RECORDING_LABEL_WIDTH } : undefined}>
            {totalMs > 0 && <TimeAxis totalMs={totalMs} tickInterval={tickInterval} />}
          </div>

          {hasTrace && (
            <div style={hasRecording ? { paddingLeft: RECORDING_LABEL_WIDTH } : undefined}>
              <SessionTrace
                metrics={metrics}
                onSeek={hasRecording ? handleSeek : undefined}
                onTurnClick={onTurnClick}
                hideHeader
                hideTimeAxis
                embedded
                sharedTotalMs={totalMs}
                sharedTickInterval={tickInterval}
                sharedOffsetMs={recordingOffsetMs}
              />
            </div>
          )}

          {hasRecording && (
            <div
              className="absolute top-0 bottom-0 pointer-events-none z-10"
              style={{ left: RECORDING_LABEL_WIDTH, right: 0 }}
            >
              <div
                ref={cursorRef}
                className="absolute top-0 bottom-0 w-px bg-secondary"
                style={{ left: `${totalMs > 0 ? (currentTimeMs / totalMs) * 100 : 0}%` }}
              />
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

import { Loader2, Pause, Play, Volume2, VolumeX } from 'lucide-react'
import { useEffect, useRef, useState } from 'react'
import { createPortal } from 'react-dom'
import WaveSurfer from 'wavesurfer.js'

/* ─── WaveSurfer runtime helper ───────────────────────────────
 * wavesurfer.js v7 inherits play/pause/isPlaying/setTime from
 * its Player base class, but the published types are incomplete
 * under skipLibCheck. We cast through `any` at call-sites via
 * this thin wrapper so the rest of the code stays type-safe.
 * ─────────────────────────────────────────────────────────── */

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type WS = any

function toWS(instance: WaveSurfer): WS {
  return instance as WS
}

/* ─── Static config ──────────────────────────────────────── */

export const RECORDING_LABEL_WIDTH = 72

interface RecordingPlayerProps {
  recordUrl: string | null | undefined
  embedded?: boolean
  labelWidth?: number
  onTimeUpdate?: (currentTimeMs: number) => void
  onReady?: (durationMs: number) => void
  onSeek?: (timeMs: number) => void
  currentTimeMs?: number
  controlsContainer?: HTMLElement | null
  timelineDurationMs?: number
}

type LoadState = 'idle' | 'loading' | 'ready' | 'error'

const SPEEDS = [1, 1.5, 2] as const
type Speed = (typeof SPEEDS)[number]

/* WaveSurfer assigns wave/progress colors directly to canvas fillStyle,
 * which doesn't resolve CSS `var()` (vars are CSS-context only). So we
 * read the `H S% L%` triple via getComputedStyle and build literal
 * `hsl(...)` strings. Re-resolve on theme change since wavesurfer
 * caches the parsed color at paint time.
 *
 * Monochrome design: user voice is the lighter ink (muted-foreground),
 * agent voice is the darker ink (foreground). Differentiation by
 * weight, not hue. */
function readVar(name: string): string {
  const v = getComputedStyle(document.documentElement).getPropertyValue(name).trim()
  return v || '0 0% 50%'
}

function resolveColors() {
  const muted = readVar('--muted-foreground')
  const fg = readVar('--foreground')
  const primary = readVar('--primary')
  return {
    userWave: `hsl(${muted} / 0.55)`,
    userProgress: `hsl(${muted})`,
    agentWave: `hsl(${fg} / 0.45)`,
    agentProgress: `hsl(${fg})`,
    cursor: `hsl(${primary})`,
  }
}

const SHARED_WS_OPTIONS = {
  height: 36,
  barWidth: 2,
  barGap: 1,
  barRadius: 2,
  cursorWidth: 0,
  normalize: true,
  interact: true,
  dragToSeek: true,
} as const

/* ─── Helpers ────────────────────────────────────────────── */

function formatTime(seconds: number): string {
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`
}

/* ─── Channel label + waveform row ──────────────────────── */

function ChannelRow({
  label,
  containerRef,
  labelColor,
  labelWidth,
  waveformWidthPct,
}: {
  label: string
  containerRef: React.RefObject<HTMLDivElement | null>
  labelColor: string
  labelWidth: number
  waveformWidthPct?: string
}) {
  return (
    <div className="flex items-center">
      <span
        className="text-[12px] shrink-0 text-right pr-2"
        style={{ color: labelColor, width: labelWidth }}
      >
        {label}
      </span>
      <div className="flex-1 min-w-0">
        <div ref={containerRef} style={waveformWidthPct ? { width: waveformWidthPct } : undefined} />
      </div>
    </div>
  )
}

/* ─── RecordingPlayer ────────────────────────────────────── */

export function RecordingPlayer({
  recordUrl,
  embedded = false,
  labelWidth = RECORDING_LABEL_WIDTH,
  onTimeUpdate,
  onReady,
  onSeek,
  currentTimeMs,
  controlsContainer,
  timelineDurationMs,
}: RecordingPlayerProps) {
  const userContainerRef = useRef<HTMLDivElement>(null)
  const agentContainerRef = useRef<HTMLDivElement>(null)
  const audioRef = useRef<HTMLAudioElement | null>(null)
  const userWsRef = useRef<WS | null>(null)
  const agentWsRef = useRef<WS | null>(null)
  const durationRef = useRef<number>(0)
  const isInternalSeekRef = useRef(false)
  const agentClickCleanupRef = useRef<(() => void) | null>(null)

  const [loadState, setLoadState] = useState<LoadState>('idle')
  const [isPlaying, setIsPlaying] = useState(false)
  const [currentTime, setCurrentTime] = useState(0)
  const [duration, setDuration] = useState(0)
  const [volume, setVolume] = useState(1)
  const [isMuted, setIsMuted] = useState(false)
  const [speed, setSpeed] = useState<Speed>(1)

  useEffect(() => {
    if (!recordUrl) return
    if (!userContainerRef.current || !agentContainerRef.current) return

    let cancelled = false
    setLoadState('loading')
    setCurrentTime(0)
    setDuration(0)
    setIsPlaying(false)

    const run = async () => {
      try {
        const response = await fetch(recordUrl)
        if (cancelled) return
        const arrayBuffer = await response.arrayBuffer()
        if (cancelled) return

        const audioCtx = new AudioContext()
        const stereoBuffer = await audioCtx.decodeAudioData(arrayBuffer)
        await audioCtx.close()
        if (cancelled) return

        const { numberOfChannels } = stereoBuffer
        const leftChannelData = stereoBuffer.getChannelData(0)
        const rightChannelData = stereoBuffer.getChannelData(Math.min(1, numberOfChannels - 1))
        const audioDuration = stereoBuffer.duration

        const audio = new Audio()
        audio.crossOrigin = 'anonymous'
        audio.src = recordUrl
        audio.preload = 'auto'
        audioRef.current = audio

        const colors = resolveColors()
        const userWs = toWS(
          WaveSurfer.create({
            container: userContainerRef.current as HTMLDivElement,
            waveColor: colors.userWave,
            progressColor: colors.userProgress,
            cursorColor: colors.cursor,
            ...SHARED_WS_OPTIONS,
            ...({
              media: audio,
              peaks: [leftChannelData],
              duration: audioDuration,
            } as Record<string, unknown>),
          }),
        )

        const agentWs = toWS(
          WaveSurfer.create({
            container: agentContainerRef.current as HTMLDivElement,
            waveColor: colors.agentWave,
            progressColor: colors.agentProgress,
            cursorColor: colors.cursor,
            ...SHARED_WS_OPTIONS,
            ...({
              peaks: [rightChannelData],
              duration: audioDuration,
              interact: false,
            } as Record<string, unknown>),
          }),
        )

        userWsRef.current = userWs
        agentWsRef.current = agentWs
        durationRef.current = audioDuration

        userWs.on('audioprocess', () => {
          const t = userWs.getCurrentTime()
          setCurrentTime(t)
          agentWs.seekTo(t / audioDuration)
          isInternalSeekRef.current = true
          onTimeUpdate?.(t * 1000)
          isInternalSeekRef.current = false
        })
        userWs.on('seeking', () => {
          const t = userWs.getCurrentTime()
          setCurrentTime(t)
          agentWs.seekTo(t / audioDuration)
          isInternalSeekRef.current = true
          onTimeUpdate?.(t * 1000)
          onSeek?.(t * 1000)
          isInternalSeekRef.current = false
        })
        userWs.on('play', () => setIsPlaying(true))
        userWs.on('pause', () => setIsPlaying(false))
        userWs.on('finish', () => {
          setIsPlaying(false)
          setCurrentTime(0)
        })

        const agentEl = agentContainerRef.current
        const handleAgentClick = (e: MouseEvent) => {
          const rect = agentEl?.getBoundingClientRect()
          if (!rect) return
          const progress = (e.clientX - rect.left) / rect.width
          userWs.seekTo(progress)
        }
        agentEl?.addEventListener('click', handleAgentClick)
        agentClickCleanupRef.current = () => agentEl?.removeEventListener('click', handleAgentClick)

        setDuration(audioDuration)
        setLoadState('ready')
        onReady?.(audioDuration * 1000)

        audio.volume = isMuted ? 0 : volume
        audio.playbackRate = speed
      } catch {
        if (!cancelled) setLoadState('error')
      }
    }

    run()

    return () => {
      cancelled = true
      agentClickCleanupRef.current?.()
      agentClickCleanupRef.current = null
      userWsRef.current?.destroy()
      agentWsRef.current?.destroy()
      userWsRef.current = null
      agentWsRef.current = null
      durationRef.current = 0
      if (audioRef.current) {
        audioRef.current.pause()
        audioRef.current.src = ''
        audioRef.current = null
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [recordUrl])

  useEffect(() => {
    if (currentTimeMs === undefined) return
    if (isInternalSeekRef.current) return
    const userWs = userWsRef.current
    const dur = durationRef.current
    if (!userWs || dur <= 0) return
    userWs.seekTo(currentTimeMs / (dur * 1000))
  }, [currentTimeMs])

  /* WaveSurfer caches resolved colors at draw time, so a `dark` class
   * toggle on <html> won't repaint the canvas with the new theme's
   * variables. Watch the class change, re-resolve CSS variables (canvas
   * can't read them), and re-set the colors. */
  useEffect(() => {
    const root = document.documentElement
    const repaint = () => {
      const userWs = userWsRef.current
      const agentWs = agentWsRef.current
      const c = resolveColors()
      if (userWs) {
        userWs.setOptions({
          waveColor: c.userWave,
          progressColor: c.userProgress,
          cursorColor: c.cursor,
        })
      }
      if (agentWs) {
        agentWs.setOptions({
          waveColor: c.agentWave,
          progressColor: c.agentProgress,
          cursorColor: c.cursor,
        })
      }
    }
    const observer = new MutationObserver((mutations) => {
      for (const m of mutations) {
        if (m.type === 'attributes' && m.attributeName === 'class') {
          repaint()
          break
        }
      }
    })
    observer.observe(root, { attributes: true, attributeFilter: ['class'] })
    return () => observer.disconnect()
  }, [loadState])

  useEffect(() => {
    if (!audioRef.current || loadState !== 'ready') return
    audioRef.current.volume = isMuted ? 0 : volume
  }, [volume, isMuted, loadState])

  useEffect(() => {
    if (!audioRef.current || loadState !== 'ready') return
    audioRef.current.playbackRate = speed
  }, [speed, loadState])

  const handlePlayPause = () => {
    const player = userWsRef.current
    if (!player) return
    if (isPlaying) {
      player.pause()
    } else {
      player.play().catch(() => undefined)
    }
  }

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = Number(e.target.value)
    setVolume(v)
    setIsMuted(v === 0)
  }

  const handleMuteToggle = () => setIsMuted((prev) => !prev)

  const cycleSpeed = () => {
    setSpeed((prev) => {
      const idx = SPEEDS.indexOf(prev)
      return SPEEDS[(idx + 1) % SPEEDS.length]
    })
  }

  if (!recordUrl) {
    if (embedded) return null
    return (
      <div className="rounded-lg border bg-card p-4">
        <p className="text-[12px] text-muted-foreground">No recording available</p>
      </div>
    )
  }

  const waveformWidthPct =
    timelineDurationMs && timelineDurationMs > 0 && duration > 0
      ? `${((duration * 1000) / timelineDurationMs) * 100}%`
      : undefined

  const waveformArea = (
    <div className="flex flex-col gap-2 relative">
      {loadState === 'loading' && (
        <div className="absolute inset-0 flex items-center justify-center bg-card/80 z-10 rounded">
          <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
        </div>
      )}
      {loadState === 'error' && (
        <div className="flex items-center justify-center py-8">
          <p className="text-[12px] text-muted-foreground">Failed to load recording</p>
        </div>
      )}
      <ChannelRow
        label="User"
        containerRef={userContainerRef}
        labelColor="hsl(var(--muted-foreground))"
        labelWidth={labelWidth}
        waveformWidthPct={waveformWidthPct}
      />
      <ChannelRow
        label="Agent"
        containerRef={agentContainerRef}
        labelColor="hsl(var(--foreground))"
        labelWidth={labelWidth}
        waveformWidthPct={waveformWidthPct}
      />
    </div>
  )

  const controlsArea = (
    <div
      className="flex items-center gap-3"
      style={!controlsContainer && embedded ? { paddingLeft: labelWidth } : undefined}
    >
      <button
        onClick={handlePlayPause}
        disabled={loadState !== 'ready'}
        className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-primary text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
        aria-label={isPlaying ? 'Pause' : 'Play'}
      >
        {isPlaying ? <Pause className="h-3.5 w-3.5" /> : <Play className="h-3.5 w-3.5" />}
      </button>

      <span className="text-[12px] text-muted-foreground tabular-nums">
        {formatTime(currentTime)} / {formatTime(duration)}
      </span>

      <div className="flex items-center gap-1.5 ml-auto">
        <button
          onClick={handleMuteToggle}
          className="shrink-0 text-muted-foreground hover:text-foreground transition-colors"
          aria-label={isMuted ? 'Unmute' : 'Mute'}
        >
          {isMuted || volume === 0 ? (
            <VolumeX className="h-4 w-4" />
          ) : (
            <Volume2 className="h-4 w-4" />
          )}
        </button>

        <input
          type="range"
          min={0}
          max={1}
          step={0.02}
          value={isMuted ? 0 : volume}
          onChange={handleVolumeChange}
          className="w-16 h-1 accent-primary cursor-pointer"
          aria-label="Volume"
        />

        <button
          onClick={cycleSpeed}
          className="ml-1 w-8 text-center text-[12px] text-muted-foreground hover:text-foreground transition-colors tabular-nums"
          aria-label={`Playback speed ${speed}x`}
        >
          {speed}x
        </button>
      </div>
    </div>
  )

  if (embedded) {
    return (
      <>
        {controlsContainer && createPortal(controlsArea, controlsContainer)}
        <div className="flex flex-col gap-3">
          {!controlsContainer && controlsArea}
          {waveformArea}
        </div>
      </>
    )
  }

  return (
    <>
      {controlsContainer && createPortal(controlsArea, controlsContainer)}
      <div className="rounded-lg border bg-card p-4 flex flex-col gap-3">
        {!controlsContainer && controlsArea}
        {waveformArea}
      </div>
    </>
  )
}

import { memo, useCallback, useMemo, useState } from 'react'
import { formatMs } from '@/lib/observability-format'
import type { SessionMetrics, TurnRecord } from '@/lib/observability-types'

// ─── Constants ────────────────────────────────────────────────────────────────

// Monochrome: every span uses the neutral scale. Pipeline stages are
// differentiated by density (solid vs translucent fill) rather than hue,
// and labels always land on foreground/muted-foreground.
const SPAN_COLORS = {
  user: { bg: 'bg-muted', border: 'border-border', label: 'text-muted-foreground' },
  agent: { bg: 'bg-foreground/15', border: 'border-foreground/30', label: 'text-foreground' },
  stt: { bg: 'bg-foreground/10', border: 'border-foreground/25', label: 'text-muted-foreground' },
  turn_decision: { bg: 'bg-foreground/5', border: 'border-foreground/20', label: 'text-muted-foreground' },
  llm: { bg: 'bg-foreground/15', border: 'border-foreground/30', label: 'text-foreground' },
  tts: { bg: 'bg-foreground/10', border: 'border-foreground/25', label: 'text-muted-foreground' },
} as const

const ROW_HEIGHT = 28
const PIPELINE_ROW_HEIGHT = 22

// ─── Types ────────────────────────────────────────────────────────────────────

interface TimeSpan {
  startMs: number
  endMs: number
  turnIndex: number
  turnNumber: number
  text: string | null
}

interface PipelineSpan {
  kind: 'stt' | 'turn_decision' | 'llm' | 'tts'
  startMs: number
  endMs: number
  durationMs: number
}

interface ProcessedTurn {
  turnNumber: number
  turnIndex: number
  userSpan: TimeSpan | null
  agentSpan: TimeSpan | null
  pipelineSpans: PipelineSpan[]
  userText: string | null
  agentText: string | null
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

export const parseMs = (iso: string | undefined): number | null => {
  if (!iso) return null
  const t = new Date(iso).getTime()
  return isNaN(t) ? null : t
}

const clamp = (v: number, min: number, max: number) => Math.max(min, Math.min(max, v))

export const computeTickInterval = (totalMs: number): number => {
  if (totalMs <= 20_000) return 2000
  if (totalMs <= 60_000) return 5000
  if (totalMs <= 180_000) return 10_000
  return 30_000
}

// ─── Session bounds ───────────────────────────────────────────────────────────

export interface SessionBounds {
  sessionStartMs: number
  sessionEndMs: number
  totalMs: number
  tickInterval: number
}

export const computeSessionBounds = (metrics: SessionMetrics | null): SessionBounds => {
  const empty: SessionBounds = { sessionStartMs: 0, sessionEndMs: 0, totalMs: 0, tickInterval: 0 }
  if (!metrics?.turns?.length) return empty

  let sessionStartMs = Infinity
  let sessionEndMs = -Infinity

  for (const t of metrics.turns) {
    for (const iso of [
      t.user_started_speaking_at,
      t.user_stopped_speaking_at,
      t.agent_started_speaking_at,
      t.agent_stopped_speaking_at,
    ]) {
      const v = parseMs(iso)
      if (v != null) {
        if (v < sessionStartMs) sessionStartMs = v
        if (v > sessionEndMs) sessionEndMs = v
      }
    }

    const agentStart = parseMs(t.agent_started_speaking_at)
    if (agentStart != null) {
      const end =
        parseMs(t.agent_stopped_speaking_at) ?? agentStart + (t.tts_audio_duration_ms ?? 2000)
      if (end > sessionEndMs) sessionEndMs = end
    }
  }

  if (sessionStartMs === Infinity) return empty

  const durationMs = sessionEndMs - sessionStartMs
  const tickInterval = computeTickInterval(durationMs)
  const totalMs = Math.ceil(durationMs / 1000) * 1000 + tickInterval

  return { sessionStartMs, sessionEndMs, totalMs, tickInterval }
}

// ─── Pipeline span builder ───────────────────────────────────────────────────

const buildPipelineSpans = (
  t: TurnRecord,
  sessionStartMs: number,
  userStopRelMs: number | null,
  agentStartRelMs: number | null,
): PipelineSpan[] => {
  const spans: PipelineSpan[] = []
  const toRelMs = (unixSec: number) => unixSec * 1000 - sessionStartMs

  const hasRealTimestamps =
    t.stt_timestamp != null || t.llm_timestamp != null || t.tts_timestamp != null

  if (hasRealTimestamps) {
    if (t.stt_timestamp != null && t.stt_delay_ms && t.stt_delay_ms > 0) {
      const sttEnd = toRelMs(t.stt_timestamp)
      const sttStart = sttEnd - t.stt_delay_ms
      spans.push({ kind: 'stt', startMs: sttStart, endMs: sttEnd, durationMs: t.stt_delay_ms })
    }

    if (t.turn_decision_ms && t.turn_decision_ms > 0 && t.stt_timestamp != null) {
      const decStart = toRelMs(t.stt_timestamp)
      spans.push({
        kind: 'turn_decision',
        startMs: decStart,
        endMs: decStart + t.turn_decision_ms,
        durationMs: t.turn_decision_ms,
      })
    }

    if (t.llm_timestamp != null) {
      const llmStart = toRelMs(t.llm_timestamp)
      const llmDur = t.llm_duration_ms ?? t.llm_ttft_ms ?? 0
      if (llmDur > 0) {
        spans.push({ kind: 'llm', startMs: llmStart, endMs: llmStart + llmDur, durationMs: llmDur })
      }
    }

    if (t.tts_timestamp != null) {
      const ttsStart = toRelMs(t.tts_timestamp)
      const ttsDur = t.tts_audio_duration_ms ?? t.tts_ttfb_ms ?? 0
      if (ttsDur > 0) {
        spans.push({ kind: 'tts', startMs: ttsStart, endMs: ttsStart + ttsDur, durationMs: ttsDur })
      }
    }
  } else if (userStopRelMs != null) {
    const sttDur = t.stt_delay_ms
    const decisionDur = t.turn_decision_ms
    const llmDur = t.llm_duration_ms ?? t.llm_ttft_ms
    const ttsDur = t.tts_audio_duration_ms ?? t.tts_ttfb_ms

    if (sttDur != null && sttDur > 0) {
      const sttStart = userStopRelMs
      spans.push({ kind: 'stt', startMs: sttStart, endMs: sttStart + sttDur, durationMs: sttDur })

      let cursor = sttStart + sttDur

      if (decisionDur != null && decisionDur > 0) {
        spans.push({
          kind: 'turn_decision',
          startMs: cursor,
          endMs: cursor + decisionDur,
          durationMs: decisionDur,
        })
        cursor += decisionDur
      }

      if (llmDur != null && llmDur > 0) {
        spans.push({ kind: 'llm', startMs: cursor, endMs: cursor + llmDur, durationMs: llmDur })

        if (ttsDur != null && ttsDur > 0) {
          const ttsStart = cursor + (t.llm_ttft_ms ?? 0)
          spans.push({ kind: 'tts', startMs: ttsStart, endMs: ttsStart + ttsDur, durationMs: ttsDur })
        }
      }
    }
  }

  if (spans.length === 0 && t.agent_first && agentStartRelMs != null) {
    const ttsDur = t.tts_audio_duration_ms ?? t.tts_ttfb_ms
    if (ttsDur && ttsDur > 0) {
      spans.push({
        kind: 'tts',
        startMs: agentStartRelMs,
        endMs: agentStartRelMs + ttsDur,
        durationMs: ttsDur,
      })
    }
  }

  return spans
}

// ─── Tooltip ──────────────────────────────────────────────────────────────────

interface TooltipState {
  x: number
  y: number
  turnNumber: number
  label: string
  durationMs: number
  text: string | null
}

function TraceTooltip({ tip }: { tip: TooltipState }) {
  return (
    <div
      className="pointer-events-none fixed z-50 rounded-md border bg-background p-2.5 shadow-lg text-[11px] max-w-[260px]"
      style={{ left: tip.x + 12, top: tip.y - 8 }}
    >
      <div className="flex items-center justify-between gap-3 mb-1">
        <span className="font-medium text-foreground">
          Turn {tip.turnNumber} · {tip.label}
        </span>
        <span className="text-muted-foreground tabular-nums">{formatMs(tip.durationMs)}</span>
      </div>
      {tip.text && <p className="text-muted-foreground leading-snug line-clamp-3">{tip.text}</p>}
    </div>
  )
}

// ─── Span Block ───────────────────────────────────────────────────────────────

interface SpanBlockProps {
  left: number
  width: number
  colorClass: { bg: string; border: string; label: string }
  label?: string
  height?: number
  onMouseEnter: (e: React.MouseEvent) => void
  onMouseLeave: () => void
  onClick?: () => void
}

function SpanBlock({
  left,
  width,
  colorClass,
  label,
  height = ROW_HEIGHT,
  onMouseEnter,
  onMouseLeave,
  onClick,
}: SpanBlockProps) {
  return (
    <div
      className={[
        'absolute top-1/2 -translate-y-1/2 rounded border cursor-default select-none',
        colorClass.bg,
        colorClass.border,
        onClick ? 'cursor-pointer' : '',
      ].join(' ')}
      style={{ left: `${left * 100}%`, width: `max(3px, ${width * 100}%)`, height: height - 6 }}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      onClick={onClick}
    >
      {label && width > 0.04 && (
        <span
          className={[
            'absolute inset-0 flex items-center px-1.5 text-[10px] font-medium truncate',
            colorClass.label,
          ].join(' ')}
        >
          {label}
        </span>
      )}
    </div>
  )
}

// ─── Time Axis ────────────────────────────────────────────────────────────────

export function TimeAxis({ totalMs, tickInterval }: { totalMs: number; tickInterval: number }) {
  const ticks: number[] = []
  for (let t = 0; t <= totalMs; t += tickInterval) ticks.push(t)
  if (ticks[ticks.length - 1] < totalMs) ticks.push(totalMs)

  return (
    <div className="relative h-6 mb-1">
      {ticks.map((t) => {
        const pct = totalMs > 0 ? (t / totalMs) * 100 : 0
        return (
          <div
            key={t}
            className="absolute flex flex-col items-center"
            style={{ left: `${pct}%`, transform: 'translateX(-50%)' }}
          >
            <span className="text-[10px] text-muted-foreground tabular-nums whitespace-nowrap">
              {t === 0 ? '0s' : `${(t / 1000).toFixed(0)}s`}
            </span>
            <div className="w-px h-1.5 bg-border mt-0.5" />
          </div>
        )
      })}
      <div className="absolute bottom-0 left-0 right-0 h-px bg-border" />
    </div>
  )
}

// ─── Grid Lines ───────────────────────────────────────────────────────────────

function GridLines({ totalMs, tickInterval }: { totalMs: number; tickInterval: number }) {
  const ticks: number[] = []
  for (let t = tickInterval; t < totalMs; t += tickInterval) ticks.push(t)

  return (
    <>
      {ticks.map((t) => (
        <div
          key={t}
          className="absolute inset-y-0 w-px bg-border/40"
          style={{ left: `${(t / totalMs) * 100}%` }}
        />
      ))}
    </>
  )
}

function TraceRow({ height = ROW_HEIGHT, children }: { height?: number; children: React.ReactNode }) {
  return (
    <div className="relative" style={{ height }}>
      {children}
    </div>
  )
}

// ─── Span row config ──────────────────────────────────────────────────────────

const SPAN_ROWS = [
  {
    key: 'user' as const,
    getSpan: (pt: ProcessedTurn) => pt.userSpan,
    colors: SPAN_COLORS.user,
    prefix: 'User',
    tooltip: 'User speech',
    getText: (pt: ProcessedTurn) => pt.userText,
    delay: 500,
    buffer: { before: 300, after: 300 },
  },
  {
    key: 'agent' as const,
    getSpan: (pt: ProcessedTurn) => pt.agentSpan,
    colors: SPAN_COLORS.agent,
    prefix: 'Agent',
    tooltip: 'Agent speech',
    getText: (pt: ProcessedTurn) => pt.agentText,
    delay: 1000,
    buffer: { before: 0, after: 500 },
  },
]

const pipelineLabelMap: Record<PipelineSpan['kind'], string> = {
  stt: 'STT',
  turn_decision: 'Decision',
  llm: 'LLM',
  tts: 'TTS',
}

const kindRows: Array<PipelineSpan['kind']> = ['stt', 'turn_decision', 'llm', 'tts']

// ─── Trace Content (memoized) ─────────────────────────────────────────────────

interface TraceContentProps {
  processedTurns: ProcessedTurn[]
  sortedExpandedTurns: number[]
  turnMap: Map<number, ProcessedTurn>
  totalMs: number
  tickInterval: number
  offsetMs: number
  currentTimeMs?: number
  onSeek?: (timeMs: number) => void
  onTurnClick?: (turnNumber: number) => void
  showTip: (e: React.MouseEvent, turnNumber: number, label: string, durationMs: number, text: string | null) => void
  hideTip: () => void
  toggleTurn: (turnNumber: number) => void
}

const TraceContent = memo(
  ({
    processedTurns,
    sortedExpandedTurns,
    turnMap,
    totalMs,
    tickInterval,
    offsetMs,
    currentTimeMs,
    onSeek,
    onTurnClick,
    showTip,
    hideTip,
    toggleTurn,
  }: TraceContentProps) => {
    const toFrac = (ms: number) => clamp((ms + offsetMs) / totalMs, 0, 1)
    const spanWidth = (start: number, end: number) => clamp(toFrac(end) - toFrac(start), 0, 1)

    const handleTraceClick = (e: React.MouseEvent<HTMLDivElement>) => {
      if (!onSeek) return
      const rect = e.currentTarget.getBoundingClientRect()
      const relX = e.clientX - rect.left
      const timeMs = clamp((relX / rect.width) * totalMs, 0, totalMs)
      onSeek(timeMs)
    }

    return (
      <div
        className="relative"
        onClick={onSeek ? handleTraceClick : undefined}
        style={{ cursor: onSeek ? 'crosshair' : undefined }}
      >
        {SPAN_ROWS.map(({ key, getSpan, colors, prefix, tooltip: tooltipLabel, getText, delay, buffer }) => (
          <TraceRow key={key}>
            <GridLines totalMs={totalMs} tickInterval={tickInterval} />
            {processedTurns.map((pt) => {
              const s = getSpan(pt)
              if (!s) return null
              const visStart = Math.max(0, s.startMs + delay - buffer.before)
              const visEnd = s.endMs + delay + buffer.after
              const left = toFrac(visStart)
              const width = spanWidth(visStart, visEnd)
              return (
                <SpanBlock
                  key={pt.turnNumber}
                  left={left}
                  width={width}
                  colorClass={colors}
                  label={`${prefix} T${s.turnNumber}`}
                  height={ROW_HEIGHT}
                  onMouseEnter={(e) => showTip(e, s.turnNumber, tooltipLabel, s.endMs - s.startMs, getText(pt))}
                  onMouseLeave={hideTip}
                  onClick={() => {
                    if (pt.pipelineSpans.length) toggleTurn(pt.turnNumber)
                    onTurnClick?.(pt.turnNumber)
                  }}
                />
              )
            })}
          </TraceRow>
        ))}

        {sortedExpandedTurns.map((turnNumber) => {
          const pt = turnMap.get(turnNumber)
          if (!pt || !pt.pipelineSpans.length) return null

          return kindRows.map((kind) => {
            const spans = pt.pipelineSpans.filter((s) => s.kind === kind)
            if (!spans.length) return null
            const colors = SPAN_COLORS[kind]

            return (
              <TraceRow key={`${pt.turnNumber}-${kind}`} height={PIPELINE_ROW_HEIGHT}>
                {spans.map((s, si) => {
                  const left = toFrac(s.startMs)
                  const width = spanWidth(s.startMs, s.endMs)
                  return (
                    <SpanBlock
                      key={si}
                      left={left}
                      width={width}
                      colorClass={colors}
                      label={`${pipelineLabelMap[kind]} ${formatMs(s.durationMs)}`}
                      height={PIPELINE_ROW_HEIGHT}
                      onMouseEnter={(e) => showTip(e, pt.turnNumber, pipelineLabelMap[kind], s.durationMs, null)}
                      onMouseLeave={hideTip}
                    />
                  )
                })}
              </TraceRow>
            )
          })
        })}

        {currentTimeMs != null && currentTimeMs > 0 && (
          <div
            className="absolute top-0 bottom-0 w-px bg-primary z-10 pointer-events-none"
            style={{ left: `${(currentTimeMs / totalMs) * 100}%` }}
          />
        )}
      </div>
    )
  },
)

TraceContent.displayName = 'TraceContent'

// ─── Main Component ───────────────────────────────────────────────────────────

interface SessionTraceProps {
  metrics: SessionMetrics | null
  currentTimeMs?: number
  onSeek?: (timeMs: number) => void
  onTurnClick?: (turnNumber: number) => void
  hideHeader?: boolean
  hideTimeAxis?: boolean
  embedded?: boolean
  sharedTotalMs?: number
  sharedTickInterval?: number
  sharedOffsetMs?: number
}

export function SessionTrace({
  metrics,
  currentTimeMs,
  onSeek,
  onTurnClick,
  hideHeader,
  hideTimeAxis,
  embedded,
  sharedTotalMs,
  sharedTickInterval,
  sharedOffsetMs,
}: SessionTraceProps) {
  const [expandedTurns, setExpandedTurns] = useState<Set<number>>(new Set())
  const [tooltip, setTooltip] = useState<TooltipState | null>(null)

  const { processedTurns, bounds } = useMemo(() => {
    const bounds = computeSessionBounds(metrics)
    if (!metrics?.turns?.length || bounds.totalMs === 0)
      return { processedTurns: [] as ProcessedTurn[], bounds }

    const { sessionStartMs } = bounds
    const processed: ProcessedTurn[] = []

    for (let i = 0; i < metrics.turns.length; i++) {
      const t = metrics.turns[i]
      const userStart = parseMs(t.user_started_speaking_at)
      const userStop = parseMs(t.user_stopped_speaking_at)
      const agentStart = parseMs(t.agent_started_speaking_at)
      const agentStop = parseMs(t.agent_stopped_speaking_at)

      let userSpan: TimeSpan | null = null
      if (userStart != null && userStop != null && userStop > userStart) {
        userSpan = {
          startMs: userStart - sessionStartMs,
          endMs: userStop - sessionStartMs,
          turnIndex: i,
          turnNumber: t.turn_number,
          text: t.user_text,
        }
      }

      let agentSpan: TimeSpan | null = null
      if (agentStart != null) {
        const agentEnd = agentStop ?? agentStart + (t.tts_audio_duration_ms ?? 2000)
        agentSpan = {
          startMs: agentStart - sessionStartMs,
          endMs: agentEnd - sessionStartMs,
          turnIndex: i,
          turnNumber: t.turn_number,
          text: t.agent_text,
        }
      }

      const userStopRel = userStop != null ? userStop - sessionStartMs : null
      const agentStartRel = agentStart != null ? agentStart - sessionStartMs : null
      const pipelineSpans = buildPipelineSpans(t, sessionStartMs, userStopRel, agentStartRel)

      processed.push({
        turnNumber: t.turn_number,
        turnIndex: i,
        userSpan,
        agentSpan,
        pipelineSpans,
        userText: t.user_text,
        agentText: t.agent_text,
      })
    }

    return { processedTurns: processed, bounds }
  }, [metrics])

  const totalMs = sharedTotalMs ?? bounds.totalMs
  const tickInterval = sharedTickInterval ?? bounds.tickInterval
  const offsetMs = sharedOffsetMs ?? 0

  const turnMap = useMemo(() => {
    const map = new Map<number, ProcessedTurn>()
    for (const pt of processedTurns) map.set(pt.turnNumber, pt)
    return map
  }, [processedTurns])

  const sortedExpandedTurns = useMemo(
    () => [...expandedTurns].sort((a, b) => a - b),
    [expandedTurns],
  )

  const toggleTurn = useCallback((turnNumber: number) => {
    setExpandedTurns((prev) => {
      const next = new Set(prev)
      if (next.has(turnNumber)) next.delete(turnNumber)
      else next.add(turnNumber)
      return next
    })
  }, [])

  const showTip = useCallback(
    (e: React.MouseEvent, turnNumber: number, label: string, durationMs: number, text: string | null) => {
      setTooltip({ x: e.clientX, y: e.clientY, turnNumber, label, durationMs, text })
    },
    [],
  )

  const hideTip = useCallback(() => setTooltip(null), [])

  if (!processedTurns.length) return null

  return (
    <div className={embedded ? '' : 'rounded-lg border bg-card p-5'}>
      {!hideHeader && (
        <div className="mb-3">
          <span className="text-[14px] font-medium">Session Trace</span>
          <p className="text-[12px] text-muted-foreground mt-0.5">
            Turn-by-turn trace · click a turn to expand pipeline
          </p>
        </div>
      )}

      {!hideTimeAxis && totalMs > 0 && <TimeAxis totalMs={totalMs} tickInterval={tickInterval} />}

      <TraceContent
        processedTurns={processedTurns}
        sortedExpandedTurns={sortedExpandedTurns}
        turnMap={turnMap}
        totalMs={totalMs}
        tickInterval={tickInterval}
        offsetMs={offsetMs}
        currentTimeMs={currentTimeMs}
        onSeek={onSeek}
        onTurnClick={onTurnClick}
        showTip={showTip}
        hideTip={hideTip}
        toggleTurn={toggleTurn}
      />

      {tooltip && <TraceTooltip tip={tooltip} />}
    </div>
  )
}

import { useState } from 'react'
